#include <bits/stdc++.h>
using namespace std;
const long long INF = (long long)1e18;

vector<long long> dijkstra(int src, int N, vector<vector<pair<int,int>>>& adj) {
    vector<long long> dist(N + 1, INF);
    dist[src] = 0;
    priority_queue<pair<long long,int>, vector<pair<long long,int>>, greater<pair<long long,int>>> pq;
    pq.push({0, src});
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        if (d > dist[u]) continue;
        for (auto [v, w] : adj[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int N, M;
    cin >> N >> M;
    vector<vector<pair<int,int>>> adj(N + 1);
    for (int i = 0; i < M; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }
    int V1, V2;
    cin >> V1 >> V2;
    auto d1 = dijkstra(1, N, adj);
    auto dv1 = dijkstra(V1, N, adj);
    auto dv2 = dijkstra(V2, N, adj);
    long long ans = INF;
    long long path1 = (d1[V1] >= INF || dv1[V2] >= INF || dv2[N] >= INF) ? INF : d1[V1] + dv1[V2] + dv2[N];
    long long path2 = (d1[V2] >= INF || dv2[V1] >= INF || dv1[N] >= INF) ? INF : d1[V2] + dv2[V1] + dv1[N];
    ans = min(path1, path2);
    if (ans >= INF) cout << -1 << "\n";
    else cout << ans << "\n";
    return 0;
}
